下面是用Qt生成sin曲线的代码示例：

```cpp
#include <QtWidgets>

class MainWindow : public QMainWindow
{
public:
    MainWindow(QWidget *parent = nullptr) : QMainWindow(parent)
    {
        setWindowTitle(tr("Sin Wave"));

        QWidget *centralWidget = new QWidget(this);
        setCentralWidget(centralWidget);

        QLabel *ampLabel = new QLabel(tr("Amplitude:"), this);
        m_ampSpinBox = new QDoubleSpinBox(this);
        m_ampSpinBox->setRange(0.0, 100.0);
        m_ampSpinBox->setValue(1.0);

        QLabel *freqLabel = new QLabel(tr("Frequency:"), this);
        m_freqSpinBox = new QDoubleSpinBox(this);
        m_freqSpinBox->setRange(0.0, 100.0);
        m_freqSpinBox->setValue(1.0);

        QLabel *phaseLabel = new QLabel(tr("Phase:"), this);
        m_phaseSpinBox = new QDoubleSpinBox(this);
        m_phaseSpinBox->setRange(0.0, 2 * M_PI);
        m_phaseSpinBox->setValue(0.0);

        QPushButton *plotButton = new QPushButton(tr("Plot"), this);
        connect(plotButton, &QPushButton::clicked, this, &MainWindow::plotCurve);

        m_chartView = new QChartView(this);
        m_chartView->setRenderHint(QPainter::Antialiasing);
        m_chartView->setMinimumSize(640, 480);

        QGridLayout *gridLayout = new QGridLayout(centralWidget);
        gridLayout->addWidget(ampLabel, 0, 0);
        gridLayout->addWidget(m_ampSpinBox, 0, 1);
        gridLayout->addWidget(freqLabel, 1, 0);
        gridLayout->addWidget(m_freqSpinBox, 1, 1);
        gridLayout->addWidget(phaseLabel, 2, 0);
        gridLayout->addWidget(m_phaseSpinBox, 2, 1);
        gridLayout->addWidget(plotButton, 3, 0, 1, 2);
        gridLayout->addWidget(m_chartView, 4, 0, 1, 2);
    }

private:
    void plotCurve()
    {
        QLineSeries *series = new QLineSeries(this);
        double amplitude = m_ampSpinBox->value();
        double frequency = m_freqSpinBox->value();
        double phase = m_phaseSpinBox->value();

        for (double x = 0.0; x <= 2 * M_PI; x += 0.1)
        {
            double y = amplitude * sin(frequency * x + phase);
            *series << QPointF(x, y);
        }

        QChart *chart = new QChart();
        chart->addSeries(series);

        chart->legend()->hide();
        chart->setTitle(tr("Sin Wave"));
        chart->createDefaultAxes();

        m_chartView->setChart(chart);
    }

private:
    QDoubleSpinBox *m_ampSpinBox;
    QDoubleSpinBox *m_freqSpinBox;
    QDoubleSpinBox *m_phaseSpinBox;
    QChartView *m_chartView;
};

int main(int argc, char *argv[])
{
    QApplication app(argc, argv);
    MainWindow mainWindow;
    mainWindow.show();
    return app.exec();
}
```

代码中使用了Qt的QLineSeries和QChartView类来绘制sin曲线，通过QDoubleSpinBox类来实现用户可在界面上设置sin曲线的振幅、频率和初相位，用户点击“Plot”按钮后，程序会重新绘制sin曲线，并显示在界面上。

可以使用Qt中的QRandomGenerator类来获取随机数。QRandomGenerator可以生成伪随机数和真随机数，其中伪随机数使用的是MT19937算法。

以下是生成一个0到100之间的随机数示例：

```cpp
#include <QtGlobal>

// 生成一个0到100之间的随机数
quint32 randNum = QRandomGenerator::global()->bounded(101); 
```

以上代码中，通过QRandomGenerator::global()方法获取一个全局的QRandomGenerator实例，然后使用它的`bounded`方法来生成一个小于101的随机数。也可以使用`generate`方法来生成一组随机数，比如：

```cpp
// 生成10个0到100之间的随机数
quint32 nums[10];
QRandomGenerator::global()->generate(nums, 10 * sizeof(quint32));
for (int i = 0; i < 10; i++) {
    nums[i] = nums[i] % 101;
}
```

以上代码中，将生成10个0到100之间的随机数，存储在数组`nums`中，并通过取模运算将其限制在0到100之间。

在Qt5之前，可以使用`qrand()`函数生成随机数。该函数可以生成伪随机数，使用了线性同余算法。

以下是生成一个0到100之间的随机数示例：

```cpp
#include <QtGlobal>

// 生成一个0到100之间的随机数
int randNum = qrand() % 101; 
```

以上代码中，使用了`qrand()`函数生成一个随机数，然后通过取模运算将其限制在0到100之间。

需要注意的是，`qrand()`函数在不同的平台上会使用不同的算法，因此其生成的随机数可能不具有统计上的随机性，不可靠。因此，建议在Qt5及以上版本中使用QRandomGenerator类。

计算两点距离可以使用以下公式：

```
d = sqrt((x2 - x1) ^ 2 + (y2 - y1) ^ 2)
```

其中，(x1, y1) 和 (x2, y2) 分别是两个点的坐标，d是两点之间的距离。

以下是使用Qt计算两点距离的示例代码：

```cpp
#include <QtMath>

// 计算两点之间的距离
double distance(double x1, double y1, double x2, double y2)
{
    double dx = x2 - x1;
    double dy = y2 - y1;
    double dsquared = dx * dx + dy * dy;
    double result = qSqrt(dsquared);
    return result;
}

int main(int argc, char *argv[])
{
    double x1 = 1.0, y1 = 2.0;
    double x2 = 3.0, y2 = 4.0;
    double d = distance(x1, y1, x2, y2);
    return 0;
}
```

以上代码中，使用了Qt中的`qSqrt`函数计算平方根，其他计算过程与公式相符。在main函数中，我们传入两个点的坐标来计算它们之间的距离，返回结果存储在变量`d`中。

可以通过`QLineSeries`的`points()`方法获取所有数据点的坐标，进而将其转换为`QVector`类型的数据。

以下是将`QLineSeries`转换为`QVector<QPointF>`的示例代码：

```cpp
QLineSeries *series = new QLineSeries;
// 添加数据点
series->append(0, 0);
series->append(1, 1);
series->append(2, 2);
series->append(3, 3);

// 获取所有数据点的坐标
QVector<QPointF> points;
for (int i = 0; i < series->count(); ++i) {
    points.append(series->points().at(i));
}
```

以上代码中，首先新建一个`QLineSeries`实例`series`，并添加4个数据点。然后使用`series->points().at(i)`方法获取所有数据点的坐标，并将其添加到`QVector<QPointF>`类型的points变量中。

可以使用QScatterSeries类在QChart中画一个点。

以下是在QChart中画一个点的示例代码：

```cpp
#include <QtWidgets>
#include <QtCharts>

int main(int argc, char *argv[])
{
    QApplication app(argc, argv);
    QMainWindow window;

    // 创建QChart实例
    QChart *chart = new QChart();
    window.setCentralWidget(new QChartView(chart));

    // 创建QScatterSeries实例，并添加一个点
    QScatterSeries *series = new QScatterSeries();
    series->append(0.5, 0.5);
    // 设置点大小和颜色
    series->setMarkerSize(10);
    series->setColor(Qt::red);
    // 将QScatterSeries添加到QChart中
    chart->addSeries(series);

    // 设置坐标轴范围
    chart->createDefaultAxes();
    chart->axes(Qt::Horizontal).first()->setRange(0, 1);
    chart->axes(Qt::Vertical).first()->setRange(0, 1);

    window.show();
    return app.exec();
}
```

以上代码中，首先创建了一个QChart实例，并设置为主窗口的中央窗口。然后创建了一个QScatterSeries实例，并添加了一个点(0.5, 0.5)。并设置点的大小和颜色后将其添加到了QChart中。最后设置坐标轴范围，运行程序即可在中央窗口显示一个红色的点。

向量点积，也称为内积，在代数中表示两个向量的数量积，它的结果是一个标量。它可以用向量的长度和两个向量夹角的余弦值表示，公式为：

```
a·b = |a| × |b| × cosθ
```

其中，a和b是两个向量，|a|和|b|是它们的长度，θ是它们的夹角。

向量点积的几何意义是，在平面内，它表示两个向量之间的相似性。两个向量之间的夹角越接近90度，它们的点积就越接近于0；如果夹角小于90度，则它们的点积为正数；如果夹角大于90度，则它们的点积为负数。因此，向量点积可以用来判断两个向量是否相互垂直，或者是在同一方向上或反方向上。

向量点积的代数意义是，在计算机图形学和计算机游戏中，用于计算投影、旋转和碰撞检测等问题。它可以通过将两个向量的坐标分别相乘并求和来计算。例如，下面的代码用向量点积计算了两个向量的夹角：

```cpp
double dotProduct(QVector3D a, QVector3D b)   // 三维空间中的向量点积
{
    return a.x() * b.x() + a.y() * b.y() + a.z() * b.z();
}

double angleBetween(QVector3D a, QVector3D b)   // 计算两个向量的夹角
{
    double dot = dotProduct(a, b);
    double len = a.length() * b.length();
    return qAcos(dot / len);
}
```

以上代码中，`dotProduct`函数用于计算两个三维向量的点积，`angleBetween`函数用于计算两个向量之间的夹角。可以看出，在计算两个向量的夹角时，我们首先调用了`dotProduct`函数计算了它们的点积，然后再通过两个向量的长度和它们的点积来计算夹角。
